    65→            <div class="user-avatar company-avatar" id="user-avatar">?</div>
    66→            <div style="flex: 1; text-align: left;">
    67→              <span class="user-name" id="user-name" style="display: block; font-size: 14px; font-weight: 500;">Loading...</span>
    68→              <span class="company-name" id="company-name" style="display: block; font-size: 12px; color: var(--text-muted);">Company</span>
    69→            </div>
