    74→              <span class="dropdown-user-name" id="dropdown-user-name">Loading...</span>
    75→              <span class="dropdown-user-email" id="dropdown-user-email">user@example.com</span>
    76→            </div>
    77→            <div class="dropdown-items">
    78→              <a href="/recruiter-profile.html" class="dropdown-item">🏢 Company Profile</a>
    79→              <div class="dropdown-divider"></div>
