    87→    <main class="main-content">
    88→      <header class="page-header">
    89→        <div>
    90→          <h1>Applications</h1>
    91→          <p>Review and manage candidate applications</p>
    92→        </div>
    93→        <div class="header-actions">
    94→          <select id="job-filter" class="form-select">
    95→            <option value="">All Jobs</option>
    96→          </select>
    97→        </div>
    98→      </header>
    99→
   100→      <!-- Filter Tabs -->
   101→      <div class="filter-tabs">
   102→        <button class="filter-tab active" data-status="all">All</button>
   103→        <button class="filter-tab" data-status="applied">New</button>
   104→        <button class="filter-tab" data-status="reviewing">Reviewing</button>
   105→        <button class="filter-tab" data-status="interviewed">Interviewed</button>
   106→        <button class="filter-tab" data-status="offered">Offered</button>
   107→        <button class="filter-tab" data-status="rejected">Rejected</button>
   108→      </div>
   109→
   110→      <!-- Stats Overview -->
   111→      <div class="stats-grid">
   112→        <div class="stat-card">
   113→          <div class="stat-icon">📥</div>
   114→          <div class="stat-info">
   115→            <span class="stat-value" id="total-applications">0</span>
   116→            <span class="stat-label">Total Applications</span>
   117→          </div>
   118→        </div>
   119→        <div class="stat-card">
   120→          <div class="stat-icon">🆕</div>
   121→          <div class="stat-info">
   122→            <span class="stat-value" id="new-applications">0</span>
   123→            <span class="stat-label">New Today</span>
   124→          </div>
   125→        </div>
   126→        <div class="stat-card">
   127→          <div class="stat-icon">👀</div>
   128→          <div class="stat-info">
   129→            <span class="stat-value" id="reviewing-count">0</span>
   130→            <span class="stat-label">Under Review</span>
   131→          </div>
   132→        </div>
   133→        <div class="stat-card highlight purple">
   134→          <div class="stat-icon">✅</div>
   135→          <div class="stat-info">
   136→            <span class="stat-value" id="offered-count">0</span>
   137→            <span class="stat-label">Offers Made</span>
   138→          </div>
   139→        </div>
   140→      </div>
   141→
   142→      <!-- Applications List -->
   143→      <section class="section">
   144→        <div class="applications-list" id="applications-list">
   145→          <div class="loading-state">
   146→            <div class="spinner"></div>
   147→            <p>Loading applications...</p>
   148→          </div>
   149→        </div>
   150→      </section>
   151→    </main>
   152→  </div>
   153→
   154→  <!-- Make Offer Modal -->
   155→  <div class="modal-overlay" id="offer-modal" style="display: none;">
   156→    <div class="modal">
   157→      <div class="modal-header">
   158→        <h2>Make Job Offer</h2>
   159→        <button onclick="closeOfferModal()" class="modal-close">&times;</button>
   160→      </div>
   161→      <form id="offer-form" onsubmit="submitOffer(event)">
   162→        <div class="form-group">
   163→          <label>Candidate</label>
   164→          <p id="offer-candidate-name" style="font-weight: 600; padding: 12px 16px; background: var(--bg-elevated); border-radius: var(--radius-md);">-</p>
   165→        </div>
   166→        <div class="form-group">
   167→          <label for="offer-job-title">Job Title</label>
   168→          <input type="text" id="offer-job-title" required>
   169→        </div>
   170→        <div class="form-row">
   171→          <div class="form-group">
   172→            <label for="offer-salary">Annual Salary ($)</label>
   173→            <input type="number" id="offer-salary" required min="0" step="1000" placeholder="75000">
   174→          </div>
   175→          <div class="form-group">
   176→            <label for="offer-start-date">Start Date</label>
   177→            <input type="date" id="offer-start-date" required>
   178→          </div>
   179→        </div>
   180→        <div class="form-group">
   181→          <label for="offer-benefits">Benefits Package</label>
   182→          <textarea id="offer-benefits" rows="3" placeholder="Health insurance, 401(k) matching, PTO, etc."></textarea>
   183→        </div>
   184→        <div class="form-actions">
   185→          <button type="button" onclick="closeOfferModal()" class="btn btn-ghost">Cancel</button>
   186→          <button type="submit" class="btn btn-primary">Send Offer</button>
   187→        </div>
   188→      </form>
   189→    </div>
   190→  </div>
   191→
   192→  <script src="/js/main.js"></script>
   193→  <script>
   194→    let currentFilter = 'all';
   195→    let currentJob = '';
   196→    let applications = [];
   197→
   198→    document.addEventListener('DOMContentLoaded', async () => {
   199→      const user = await checkAuth();
   200→      if (!user) {
   201→        window.location.href = '/login.html';
   202→        return;
   203→      }
   204→      // Verify recruiter/employer role - must have company_id and appropriate role
   205→      const allowedRoles = ['employer', 'recruiter', 'hiring_manager', 'admin'];
   206→      if (!user.company_id || !allowedRoles.includes(user.role)) {
   207→        window.location.href = '/candidate-dashboard.html';
   208→        return;
   209→      }
   210→
   211→      const name = user.name || user.email.split('@')[0];
   212→      document.getElementById('user-name').textContent = name;
   213→      document.getElementById('user-avatar').textContent = name.charAt(0).toUpperCase();
   214→      document.getElementById('company-name').textContent = user.company_name || 'Company';
   215→      document.getElementById('dropdown-user-name').textContent = name;
   216→      document.getElementById('dropdown-user-email').textContent = user.email;
   217→
   218→      // Setup user menu dropdown
   219→      const userMenuToggle = document.getElementById('user-menu-toggle');
   220→      const userDropdownMenu = document.getElementById('user-dropdown-menu');
   221→      if (userMenuToggle && userDropdownMenu) {
   222→        userMenuToggle.addEventListener('click', (e) => {
   223→          e.stopPropagation();
   224→          userDropdownMenu.classList.toggle('active');
   225→        });
   226→        document.addEventListener('click', () => {
   227→          userDropdownMenu.classList.remove('active');
   228→        });
   229→      }
   230→
   231→      // Setup filter tabs
   232→      document.querySelectorAll('.filter-tab').forEach(tab => {
   233→        tab.addEventListener('click', () => {
   234→          document.querySelectorAll('.filter-tab').forEach(t => t.classList.remove('active'));
   235→          tab.classList.add('active');
   236→          currentFilter = tab.dataset.status;
   237→          renderApplications();
   238→        });
   239→      });
   240→
   241→      // Setup job filter
   242→      document.getElementById('job-filter').addEventListener('change', (e) => {
   243→        currentJob = e.target.value;
   244→        renderApplications();
   245→      });
   246→
   247→      loadJobs();
   248→      loadApplications();
   249→    });
   250→
   251→    async function loadJobs() {
   252→      try {
   253→        const data = await apiCall('/recruiter/jobs');
   254→        if (data.jobs) {
   255→          const select = document.getElementById('job-filter');
   256→          data.jobs.forEach(job => {
   257→            const option = document.createElement('option');
   258→            option.value = job.id;
   259→            option.textContent = job.title;
   260→            select.appendChild(option);
   261→          });
   262→        }
   263→      } catch (err) {
   264→        console.error('Failed to load jobs:', err);
   265→      }
   266→    }
   267→
   268→    async function loadApplications() {
   269→      try {
   270→        const data = await apiCall('/recruiter/applications');
   271→        if (data.applications) {
   272→          applications = data.applications;
   273→          updateStats(applications);
   274→          renderApplications();
   275→        }
   276→      } catch (err) {
   277→        console.error('Failed to load applications:', err);
   278→        document.getElementById('applications-list').innerHTML = `
   279→          <div class="empty-state">
   280→            <p>Failed to load applications</p>
   281→          </div>
   282→        `;
   283→      }
   284→    }
   285→
   286→    function updateStats(apps) {
   287→      document.getElementById('total-applications').textContent = apps.length;
   288→
   289→      const today = new Date().toDateString();
   290→      const newToday = apps.filter(a => new Date(a.applied_at).toDateString() === today).length;
   291→      document.getElementById('new-applications').textContent = newToday;
   292→
   293→      document.getElementById('reviewing-count').textContent =
   294→        apps.filter(a => a.status === 'reviewing').length;
   295→      document.getElementById('offered-count').textContent =
   296→        apps.filter(a => a.status === 'offered').length;
   297→    }
   298→
   299→    function renderApplications() {
   300→      const container = document.getElementById('applications-list');
   301→
   302→      let filtered = applications;
   303→      if (currentFilter !== 'all') {
   304→        filtered = filtered.filter(a => a.status === currentFilter);
   305→      }
   306→      if (currentJob) {
   307→        filtered = filtered.filter(a => a.job_id == currentJob);
   308→      }
   309→
   310→      if (filtered.length === 0) {
   311→        container.innerHTML = `
   312→          <div class="empty-state">
   313→            <p>No applications found</p>
   314→            <a href="/job-create.html" class="btn btn-primary btn-sm">Post a Job</a>
   315→          </div>
   316→        `;
   317→        return;
   318→      }
   319→
   320→      container.innerHTML = filtered.map(app => `
   321→        <div class="application-card">
   322→          <div class="application-header">
   323→            <div class="candidate-info">
   324→              <div class="candidate-avatar">${(app.candidate_name || 'U').charAt(0).toUpperCase()}</div>
   325→              <div class="candidate-details">
   326→                <h3>${app.candidate_name || 'Unknown'}</h3>
   327→                <p>${app.job_title || 'Position'}</p>
   328→              </div>
   329→            </div>
   330→            <div class="application-meta">
   331→              ${app.omniscore_at_apply ? `<span class="omniscore-badge">${app.omniscore_at_apply} OmniScore</span>` : ''}
   332→              <span class="status-badge ${app.status}">${app.status}</span>
   333→            </div>
   334→          </div>
   335→          <div class="application-body">
   336→            <div class="application-info">
   337→              <span class="info-item">📧 ${app.candidate_email || 'No email'}</span>
   338→              <span class="info-item">📅 Applied ${formatDate(app.applied_at)}</span>
   339→            </div>
   340→            ${app.cover_letter ? `<p class="cover-letter-preview">${app.cover_letter.substring(0, 150)}...</p>` : ''}
   341→          </div>
   342→          <div class="application-actions">
   343→            <button onclick="updateStatus(${app.id}, 'reviewing')" class="btn btn-ghost btn-sm" ${app.status !== 'applied' ? 'disabled' : ''}>
   344→              Review
   345→            </button>
   346→            <button onclick="scheduleInterview(${app.id})" class="btn btn-ghost btn-sm">
   347→              Schedule Interview
   348→            </button>
   349→            <button onclick="makeOffer(${app.id}, ${app.candidate_id}, '${(app.candidate_name || '').replace(/'/g, "\\'")}', '${(app.candidate_email || '').replace(/'/g, "\\'")}', ${app.job_id}, '${(app.job_title || '').replace(/'/g, "\\'")}')" class="btn btn-primary btn-sm" ${app.status === 'offered' || app.status === 'hired' ? 'disabled' : ''}>
   350→              Make Offer
   351→            </button>
   352→            <button onclick="updateStatus(${app.id}, 'rejected')" class="btn btn-ghost btn-sm danger">
   353→              Reject
   354→            </button>
   355→          </div>
   356→        </div>
   357→      `).join('');
   358→    }
   359→
   360→    function formatDate(dateStr) {
   361→      const date = new Date(dateStr);
   362→      const now = new Date();
   363→      const diff = now - date;
   364→      const days = Math.floor(diff / (1000 * 60 * 60 * 24));
   365→      if (days === 0) return 'Today';
   366→      if (days === 1) return 'Yesterday';
   367→      if (days < 7) return `${days} days ago`;
   368→      return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
   369→    }
   370→
   371→    async function updateStatus(appId, status) {
   372→      try {
   373→        const result = await apiCall(`/recruiter/applications/${appId}/status`, {
   374→          method: 'PUT',
   375→          body: JSON.stringify({ status })
   376→        });
   377→        if (result.success) {
   378→          loadApplications();
   379→        }
   380→      } catch (err) {
   381→        alert('Failed to update status');
   382→      }
   383→    }
   384→
   385→    function scheduleInterview(appId) {
   386→      window.location.href = `/recruiter-interviews.html?schedule=${appId}`;
   387→    }
   388→
   389→    // Make Offer functionality
   390→    let currentOfferData = null;
   391→
   392→    function makeOffer(appId, candidateId, candidateName, candidateEmail, jobId, jobTitle) {
   393→      currentOfferData = { appId, candidateId, candidateName, candidateEmail, jobId, jobTitle };
   394→
   395→      // Pre-fill the modal
   396→      document.getElementById('offer-candidate-name').textContent = candidateName;
   397→      document.getElementById('offer-job-title').value = jobTitle;
   398→
   399→      // Set default start date to 2 weeks from now
   400→      const startDate = new Date();
   401→      startDate.setDate(startDate.getDate() + 14);
   402→      document.getElementById('offer-start-date').value = startDate.toISOString().split('T')[0];
   403→
   404→      // Show modal
   405→      document.getElementById('offer-modal').style.display = 'flex';
   406→    }
   407→
   408→    function closeOfferModal() {
   409→      document.getElementById('offer-modal').style.display = 'none';
   410→      document.getElementById('offer-form').reset();
   411→      currentOfferData = null;
   412→    }
   413→
   414→    async function submitOffer(e) {
   415→      e.preventDefault();
   416→
   417→      if (!currentOfferData) return;
   418→
   419→      const offerData = {
   420→        candidate_id: currentOfferData.candidateId,
   421→        job_id: currentOfferData.jobId,
   422→        title: document.getElementById('offer-job-title').value,
   423→        salary: parseFloat(document.getElementById('offer-salary').value),
   424→        start_date: document.getElementById('offer-start-date').value,
   425→        benefits: document.getElementById('offer-benefits').value
   426→      };
   427→
   428→      try {
   429→        // Create the offer
   430→        const createResult = await apiCall('/onboarding/offers', {
   431→          method: 'POST',
   432→          body: JSON.stringify(offerData)
   433→        });
   434→
   435→        if (!createResult || createResult.error) {
   436→          throw new Error(createResult?.error || 'Failed to create offer');
   437→        }
   438→
   439→        // Send the offer immediately
   440→        const sendResult = await apiCall(`/onboarding/offers/${createResult.id}/send`, {
   441→          method: 'POST'
   442→        });
   443→
   444→        // Update application status
   445→        await apiCall(`/recruiter/applications/${currentOfferData.appId}/status`, {
   446→          method: 'PUT',
   447→          body: JSON.stringify({ status: 'offered' })
   448→        });
   449→
   450→        alert('Offer sent successfully to ' + currentOfferData.candidateName + '!');
   451→        closeOfferModal();
   452→        loadApplications();
   453→      } catch (err) {
   454→        console.error('Error creating offer:', err);
   455→        alert('Failed to create offer: ' + err.message);
   456→      }
   457→    }
   458→  </script>
