   776→    function renderStep() {
   777→      renderStepIndicator();
   778→      const container = document.getElementById('stepContent');
   779→
   780→      switch (currentStep) {
   781→        case 1: container.innerHTML = renderStep1(); break;
   782→        case 2: container.innerHTML = renderStep2(); break;
   783→        case 3: container.innerHTML = renderStep3(); break;
   784→        case 4: container.innerHTML = renderStep4(); break;
   785→        case 5: container.innerHTML = renderStep5(); break;
   786→      }
   787→
   788→      if (currentStep === 4) {
   789→        initSignatureCanvas();
   790→      }
   791→    }
