   793→    function renderStepIndicator() {
   794→      const stepsCompleted = wizardState ? (wizardState.steps_completed || []) : [];
   795→      const indicator = document.getElementById('stepIndicator');
   796→      indicator.innerHTML = STEPS.map((s, i) => {
   797→        const isCompleted = stepsCompleted.includes(String(s.num)) || stepsCompleted.includes(s.num) || s.num < currentStep;
   798→        const isActive = s.num === currentStep;
   799→        const dotClass = isCompleted && !isActive ? 'completed' : (isActive ? 'active' : '');
   800→        const wrapperClass = isCompleted && !isActive ? 'completed' : (isActive ? 'active' : '');
   801→        const connector = i < STEPS.length - 1
   802→          ? `<div class="step-connector ${isCompleted ? 'completed' : ''}"></div>`
   803→          : '';
   804→        return `
   805→          <div class="step-dot-wrapper ${wrapperClass}">
